function claimReward(bytes32 leaf, bytes32[] calldata proof) external {
    bytes32 root = merkleRoot;
    require(MerkleProof.verify(proof, root, leaf));
    uint256 amount = rewards[leaf];
    token.transfer(msg.sender, amount);
}

chosen:
**Vulnerability: Double Claim / Missing Claimed Tracking**

There is no tracking of whether `leaf` has already been claimed. A user can call `claimReward` multiple times with the same valid proof and drain the contract.

**Fix — track claimed leaves:**
```solidity
mapping(bytes32 => bool) public claimed;

function claimReward(bytes32 leaf, bytes32[] calldata proof) external {
    require(!claimed[leaf], "already claimed");
    require(MerkleProof.verify(proof, merkleRoot, leaf));
    claimed[leaf] = true;
    token.transfer(msg.sender, rewards[leaf]);
}
```

