// Vulnerable: signature replay
function claim(uint256 amount, bytes calldata sig) external {
    bytes32 hash = keccak256(abi.encodePacked(msg.sender, amount));
    address signer = ECDSA.recover(hash, sig);
    require(signer == trustedSigner);
    token.transfer(msg.sender, amount);
}

chosen:
**Vulnerability: Signature Replay (SWC-121)**

The signed message only includes `msg.sender` and `amount`. The same signature is valid forever and on any chain, so a user can claim multiple times or reuse a signature from another chain.

**Fix — add nonce and chainId:**
```solidity
mapping(address => uint256) public nonces;

function claim(uint256 amount, bytes calldata sig) external {
    bytes32 hash = keccak256(abi.encodePacked(
        block.chainid, address(this), msg.sender, amount, nonces[msg.sender]++
    ));
    bytes32 ethHash = ECDSA.toEthSignedMessageHash(hash);
    require(ECDSA.recover(ethHash, sig) == trustedSigner);
    token.transfer(msg.sender, amount);
}
```

