function distributeRewards() external {
    for (uint256 i = 0; i < stakers.length; i++) {
        token.transfer(stakers[i], rewards[stakers[i]]);
    }
}

chosen:
**Vulnerability: Unbounded Loop / DoS (SWC-128)**

As `stakers.length` grows, the gas cost of this function grows linearly. Eventually it exceeds the block gas limit and the function becomes permanently uncallable — locking all rewards.

**Fix — pull-over-push pattern:**
```solidity
mapping(address => uint256) public pendingRewards;

function addReward(address staker, uint256 amount) internal {
    pendingRewards[staker] += amount;
}

function claimReward() external {
    uint256 amount = pendingRewards[msg.sender];
    pendingRewards[msg.sender] = 0;
    token.transfer(msg.sender, amount);
}
```
Each user claims their own reward in a separate transaction — no unbounded loop.

