contract Vault {
    IERC20 public token;
    mapping(address => uint256) public shares;
    uint256 public totalShares;

    function deposit(uint256 amount) external {
        uint256 newShares = totalShares == 0
            ? amount
            : amount * totalShares / token.balanceOf(address(this));
        shares[msg.sender] += newShares;
        totalShares += newShares;
        token.transferFrom(msg.sender, address(this), amount);
    }
}

chosen:
**Vulnerability: ERC-4626 Inflation Attack**

When `totalShares == 0`, the first depositor receives `amount` shares. An attacker can:
1. Deposit 1 wei → 1 share
2. Directly `transfer` (donate) 1e18 tokens to the vault
3. Now 1 share = 1e18 tokens
4. Next depositor's shares: `amount * 1 / 1e18` → rounds down to 0
5. Victim's deposit is absorbed into attacker's 1 share

**Fix — virtual shares (OpenZeppelin ERC4626 offset):**
```solidity
uint256 constant VIRTUAL_SHARES = 1e3;
uint256 constant VIRTUAL_ASSETS = 1;

function deposit(uint256 amount) external {
    uint256 supply = totalShares + VIRTUAL_SHARES;
    uint256 assets = token.balanceOf(address(this)) + VIRTUAL_ASSETS;
    uint256 newShares = amount * supply / assets;
    // ... rest of function
}
```
This makes the initial exchange rate 1000 shares per token and makes donation attacks economically infeasible.

