function flashLoan(uint256 amount) external {
    uint256 before = token.balanceOf(address(this));
    token.transfer(msg.sender, amount);
    IFlashBorrower(msg.sender).onFlashLoan(amount);
    require(token.balanceOf(address(this)) >= before, "not repaid");
}

chosen:
**Vulnerability: Reentrancy in Flash Loan / Missing Fee**

Two issues:
1. **No fee**: standard flash loans charge a fee (e.g. Aave: 0.09%). This implementation lends for free, draining the protocol's yield over time.
2. **Reentrancy**: the callback `onFlashLoan` can call other functions in this contract (e.g. re-enter `flashLoan` with `before` now = reduced balance). Add `nonReentrant` guard.

**Fix:**
```solidity
bool private locked;
modifier nonReentrant() {
    require(!locked); locked = true; _; locked = false;
}

function flashLoan(uint256 amount, uint256 fee) external nonReentrant {
    require(fee >= amount * 9 / 10000, "fee too low"); // 0.09%
    uint256 before = token.balanceOf(address(this));
    token.transfer(msg.sender, amount);
    IFlashBorrower(msg.sender).onFlashLoan(amount, fee);
    require(token.balanceOf(address(this)) >= before + fee, "not repaid");
}
```
